// Ringed Planet — vivid Jupiter/Saturn-inspired gas giant with dramatic banded
// atmosphere and multi-color ring system. Eight latitude bands cycle through
// rich oranges, burnt ochres, and warm browns. Five concentric ring bands span
// from rusty brown through icy bright white to wispy outer gray. A raised oval
// Great Red Spot storm marks the planet surface. The inner ring edge welds into
// the planet equator so the whole assembly is ONE connected manifold.
//
// Z-up, mm. Band/shell overlaps ensure volumetric welds (no touching-face splits).
// Model is tilted ~22° on its axis for the iconic posed look.

const { Manifold } = api;

const p = api.params({
  planetR:  { type: 'number', default: 20,   min: 12, max: 30, step: 1,    unit: 'mm', label: 'Planet radius' },
  ringSpan: { type: 'number', default: 2.45, min: 1.6, max: 3, step: 0.05, label: 'Ring outer (×R)' },
  bands:    { type: 'int',    default: 8,    min: 4,  max: 9,               label: 'Latitude bands' },
  tilt:     { type: 'number', default: 22,   min: 0,  max: 35, step: 1,    unit: '°', label: 'Axial tilt' },
  spot:     { type: 'boolean', default: true, label: 'Great Red Spot' },
});

const Rp      = p.planetR;
const OVER    = 0.8;   // band slab overlap (mm) — ensures volumetric weld between neighbors

// ---------------------------------------------------------------------------
// 1. Planet latitude bands — rich Jupiter palette cycling pole-to-equator
// ---------------------------------------------------------------------------
// Colors alternate between dark belts and bright zones, Jupiter-style.
// Order: pole (cream) → dark belt → bright zone → deep brown → ... → pole
// The equatorial band (index 4 of 8) is the broadest for natural appearance.
const BAND_COLORS = [
  '#ffe4b5',  // 0 — moccasin polar cap (warm cream)
  '#b8430a',  // 1 — deep rusty-orange belt (darker, more intense)
  '#f5d08a',  // 2 — golden cream zone
  '#7a3010',  // 3 — very deep mahogany belt
  '#f0a050',  // 4 — vivid warm orange equatorial zone (widest, most dramatic)
  '#c05010',  // 5 — bold burnt-orange belt
  '#fce8b0',  // 6 — pale golden zone
  '#9b3d15',  // 7 — rich sienna belt
  '#ffe0a0',  // 8 — warm ivory polar cap (mirror of pole 0)
];

// Non-uniform band heights: equatorial band (#4) is wider, polar bands narrower.
// We define custom band edges (normalized -1 to +1) then select the first p.bands of them.
// The last band always extends to 1.0 (north pole) to ensure full sphere coverage.
// Edges for 8 bands (9 boundaries), equatorial region slightly stretched:
const allEdges = [-1.0, -0.78, -0.54, -0.28, -0.06, 0.18, 0.42, 0.64, 1.0];

const planetSphere = Manifold.sphere(Rp, 96);
const zones = [];

// Use p.bands bands; clamp to available edges. Always use [-1..+1] range fully.
const nBands = Math.min(p.bands, allEdges.length - 1);
// Recompute edges evenly if fewer bands requested, else use the custom set
const bandEdges = nBands === allEdges.length - 1
  ? allEdges
  : Array.from({ length: nBands + 1 }, (_, i) => -1 + 2 * i / nBands);

for (let i = 0; i < nBands; i++) {
  const z0 = bandEdges[i]     * Rp - OVER;
  const z1 = bandEdges[i + 1] * Rp + OVER;
  const slab = Manifold.cube([4 * Rp, 4 * Rp, z1 - z0], true)
    .translate([0, 0, (z0 + z1) / 2]);
  const color = BAND_COLORS[i % BAND_COLORS.length];
  zones.push(api.label(planetSphere.intersect(slab), 'band' + i, { color }));
}

const planet = Manifold.union(zones);

// ---------------------------------------------------------------------------
// 2. Great Red Spot — a lens-shaped oval raised above the equatorial surface
// ---------------------------------------------------------------------------
let spot = Manifold.sphere(1, 1); // placeholder
let hasSpot = false;

if (p.spot) {
  // Great Red Spot: a solid oval ellipsoid centered just outside the planet surface,
  // overlapping the planet sphere by ~0.8mm so they weld cleanly on union.
  // No subtract needed — the ellipsoid sits in the equatorial belt and protrudes outward.
  const bumpH   = 2.2;   // total half-depth of ellipsoid in radial direction (mm)
  const spotRx  = 5.0;   // east-west half-width (mm) — larger for visibility
  const spotRy  = 3.2;   // north-south half-width (mm)
  const spotLat = -0.12 * Rp;   // z offset: slightly below equator

  // Place the ellipsoid so its center is at Rp + bumpH*0.5 (half inside, half outside surface).
  // Scale a sphere into the oval shape, then translate to +X face of planet.
  const spotR = Math.max(spotRx, spotRy, bumpH);
  spot = Manifold.sphere(spotR, 48)
    .scale([bumpH / spotR, spotRx / spotR, spotRy / spotR])  // X=radial, Y=east-west, Z=north-south
    .translate([Rp + bumpH * 0.35, 0, spotLat]);
  spot = api.label(spot, 'redSpot', { color: '#dd2200' });
  hasSpot = true;
}

// ---------------------------------------------------------------------------
// 3. Ring system — five concentric bands modeled on Saturn's real ring structure
// ---------------------------------------------------------------------------
// Ring stop positions (as multiples of Rp):
//   0.96 — inner edge welds into planet equator
//   1.20 — end of inner rusty C/D ring (narrow, debris-brown)
//   1.52 — end of Cassini gap gap zone (very dark gap)
//   2.00 — end of bright B ring (widest, most brilliant — icy white)
//   2.20 — end of A ring (pale gold)
//   2.45 — outer edge of wispy F/G ring (gray-beige)
//
// Ring height is intentionally thin (1.0mm) for the delicate, elegant look.
const ringInner = 0.96 * Rp;
const ringOuter = p.ringSpan * Rp;
const ringH     = 1.0;

const tube = (r, h) => Manifold.cylinder(h, r, r, 96, true);

// Full disk we'll carve into colored bands
const disk = tube(ringOuter, ringH)
  .subtract(tube(ringInner, ringH * 4));

// Five ring band boundaries: realistic Saturn-inspired proportions
const ringStops = [
  ringInner,
  1.22 * Rp,  // narrow inner debris band
  1.55 * Rp,  // dark Cassini-gap transition
  2.02 * Rp,  // WIDE bright B ring (most prominent)
  2.22 * Rp,  // pale gold A ring
  ringOuter,  // wispy outer F/G ring
];

const RING_COLORS = [
  '#9e4a14',  // C/D ring — rusty brown (dense debris closest to planet)
  '#4a2a0e',  // Cassini division — very dark reddish-brown (gap between C and B rings)
  '#f0f0f8',  // B ring — brilliant icy white (Saturn's most brilliant ring)
  '#dfc060',  // A ring — warm golden yellow (more vivid than pale)
  '#9a8070',  // F/G ring — warm gray-beige outer material
];

const ringParts = [];
for (let i = 0; i < ringStops.length - 1; i++) {
  const rIn  = ringStops[i];
  const rOut = ringStops[i + 1];
  // Annular shell slightly oversized to guarantee volumetric overlap with disk
  const shell = tube(rOut + 0.6, ringH * 4)
    .subtract(tube(rIn  - 0.6, ringH * 5));
  ringParts.push(
    api.label(disk.intersect(shell), 'ring' + i, { color: RING_COLORS[i] })
  );
}
const rings = Manifold.union(ringParts);

// ---------------------------------------------------------------------------
// 4. Assemble planet + optional spot + rings, then tilt on the axis
// ---------------------------------------------------------------------------
const bodyParts = hasSpot ? [planet, spot, rings] : [planet, rings];
const saturn = api.expectUnion(bodyParts, { expectComponents: 1 })
  .rotate([p.tilt, 0, 0]);

return saturn;
